export function validateRequest(e){if("string"!=typeof e)return{accepted:!1,reason:"Request must be text."};const t=e.trim();return 0===t.length?{accepted:!1,reason:"Request is empty — type what to build."}:t.length>200?{accepted:!1,reason:"Request is too long (max 200 characters)."}:/[<>]/.test(t)?{accepted:!1,reason:"Request must be plain text (no markup)."}:{accepted:!0,value:t}}